function (train_data, test_data, target_variable, alpha_value)  {     if (!requireNamespace("glmnet", quietly = TRUE)) {         install.packages("glmnet")     }     library(glmnet)     train_data <- as.data.frame(train_data)     X_train <- train_data[, !(names(train_data) %in% target_variable),          drop = FALSE]     y_train <- train_data[[target_variable]]     X_test <- test_data[, colnames(X_train), drop = FALSE]     X_train <- as.matrix(X_train)     X_test <- as.matrix(X_test)     y_train <- as.numeric(y_train)     lasso_model <- glmnet(X_train, y_train, alpha = alpha_value)     cv_model <- cv.glmnet(X_train, y_train, alpha = alpha_value)     best_lambda <- cv_model$lambda.min     predictions <- predict(lasso_model, s = best_lambda, newx = X_test)     rmse <- sqrt(mean((test_data[[target_variable]] - predictions)^2))     correlation <- cor(predictions, test_data[[target_variable]],          use = "complete.obs")     return(list(predictions = predictions, RMSE = rmse, correlation = correlation,          model = lasso_model)) }